        serde_json::from_str(v["content"][0]["text"].as_str().expect("text")).expect("json")
    }

    fn tool_error_msg(o: Outcome) -> String {
        let v = ok(o);
        assert_eq!(v["isError"], json!(true), "expected a tool error: {v}");
        v["content"][0]["text"].as_str().unwrap_or("").to_string()
    }

