            assert_eq!(schema["type"], json!("object"), "{name}: schema must be type object");
            assert!(schema["properties"].is_object(), "{name}: schema needs properties");
            assert!(schema.get("anyOf").is_none(), "{name}: no top-level anyOf (clients drop it)");
